# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

def lambda_handler(event, context):
    import boto3
    import requests
    from urllib.parse import urlparse

    # Get the request object from the event
    request = event['Records'][0]['cf']['request']

    # Check if X-Enrich-URL header is present
    enrich_url_header = request.get('headers', {}).get('x-enrich-url', [])

    if not enrich_url_header:
        return request

    # Extract URLs from the header
    urls_to_fetch = [url_value['value'] for url_value in enrich_url_header]

    # Fetch data from each URL
    enrich_data = {}
    for url in urls_to_fetch:
        parsed_url = urlparse(url)
        if parsed_url.scheme and parsed_url.netloc:
            try:
                response = requests.get(url)
                if response.status_code == 200:
                    enrich_data[url] = response.json()  # Assuming the response is JSON
                else:
                    enrich_data[url] = {'error': f'Failed to fetch data: {response.status_code}'}
            except Exception as e:
                enrich_data[url] = {'error': str(e)}

    # Add or update a custom header with the fetched data (e.g., X-Enriched-Data)
    if enrich_data:
        request['headers'].append({
            'key': 'x-enriched-data',
            'value': str(enrich_data)  # Convert to string for header value
        })

    return request